mapper.update:
UPDATE Users
SET name = #{name}, phone_number = #{phoneNumber}, email = #{email}
WHERE user_id = #{userId}

UPDATE Address
SET city = #{city}, state = #{state}, district = #{district}, cep = #{cep},
    street_name = #{streetName}, building_number = #{buildingNumber}, details = #{details}
WHERE address_id = #{addressId}

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM Users
    WHERE email = #{email}
)
